        start: int = (page - 1) * page_size
        end: int = start + page_size
        page_items: list[dict] = tasks[start:end]

        return {
            "items": page_items,
            "total": total,
            "page": page,
            "page_size": page_size,
            "total_pages": (total + page_size - 1) // page_size,
        }
    except ValueError:
        raise
    except Exception as e:
        raise RuntimeError(f"Failed to paginate tasks: {e}") from e
