def fetch_all_tasks(
    conn: sqlite3.Connection,
    completed: Optional[bool] = None,
) -> list[Task]:
    try:
        cursor: sqlite3.Cursor = conn.cursor()

        if completed is None:
            cursor.execute("SELECT * FROM tasks ORDER BY created_at ASC")
        else:
            cursor.execute(
                "SELECT * FROM tasks WHERE completed = ? ORDER BY created_at ASC",
                (int(completed),),
            )

        rows: list[sqlite3.Row] = cursor.fetchall()

        tasks: list[Task] = []
        for row in rows:
            try:
                task = Task(
                    id=row["id"],
                    title=row["title"],
                    description=row["description"],
                    completed=bool(row["completed"]),
                    created_at=row["created_at"],
                    tags=json.loads(row["tags"]),
                )
                tasks.append(task)
            except (json.JSONDecodeError, KeyError) as e:
                raise ValueError(f"Malformed task row in database: {e}") from e

        return tasks
    except (ValueError, TypeError):
        raise
    except sqlite3.DatabaseError as e:
        raise RuntimeError(f"Database error in fetch_all_tasks: {e}") from e
    except Exception as e:
        raise RuntimeError(f"Unexpected error in fetch_all_tasks: {e}") from e
