    conn: Optional[sqlite3.Connection] = None
    try:
        conn = sqlite3.connect(db_path, timeout=timeout)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA journal_mode=WAL")  # enables concurrent reads
        yield conn
        conn.commit()
    except sqlite3.OperationalError as e:
        if conn:
            conn.rollback()
        error_msg: str = str(e).lower()
        if "locked" in error_msg or "timeout" in error_msg:
            raise RuntimeError(
                f"Database is locked â€” another process may be writing. Retry after a moment: {e}"
            ) from e
        raise RuntimeError(f"Database operational error: {e}") from e
    except sqlite3.DatabaseError as e:
        if conn:
            conn.rollback()
        raise RuntimeError(f"Database error in connection to '{db_path}': {e}") from e
    except Exception as e:
        if conn:
            conn.rollback()
        raise RuntimeError(f"Unexpected error during DB session: {e}") from e
    finally:
        if conn:
            conn.close()
```

Key additions: `timeout=10.0` makes SQLite wait up to 10 seconds for a lock to release before raising `OperationalError`. `PRAGMA journal_mode=WAL` enables Write-Ahead Logging, allowing concurrent reads while a write is in progress. `sqlite3.OperationalError` is caught specifically and checked for lock-related messages. Full type hints throughout with `try/except` at every layer.
